  9→class AuthController extends BaseController
 10→{
 11→    protected AuthService $authService;
 12→
 13→    public function __construct()
 14→    {
 15→        $this->authService = new AuthService();
 16→    }
 17→
 18→    /**
 19→     * POST /api/auth/register
 20→     */
 21→    public function register()
 22→    {
 23→        $payload = $this->request->post();
 24→        if (empty($payload['organization_code']) && !empty($payload['invite_code'])) {
 25→            $payload['organization_code'] = $payload['invite_code'];
 26→        }
 27→
 28→        validate($payload, 'app\validate\AuthValidate.register');
 29→
 30→        $user = $this->authService->register($payload);
 31→
 32→        return json([
 33→            'code'    => 0,
 34→            'message' => 'Registration successful',
 35→            'data'    => $user->toArray(),
 36→        ], 201);
 37→    }
 38→
 39→    /**
 40→     * POST /api/auth/login
 41→     */
 42→    public function login()
 43→    {
 44→        validate($this->request->post(), 'app\validate\AuthValidate.login');
 45→
 46→        $result = $this->authService->login(
 47→            $this->request->post('email'),
 48→            $this->request->post('password'),
 49→            $this->request->post('organization_code', ''),
 50→            $this->request->ip(),
 51→            $this->request->header('User-Agent', '')
 52→        );
 53→
 54→        return json([
 55→            'code'    => 0,
 56→            'message' => 'Login successful',
 57→            'data'    => [
 58→                'user'               => $result['user']->toArray(),
 59→                'roles'              => $result['roles'],
 60→                'session_expires_at' => $result['session_expires_at'],
 61→            ],
 62→        ], 200);
