 65→    /**
 66→     * POST /api/auth/logout
 67→     */
 68→    public function logout()
 69→    {
 70→        $this->authService->logout(
 71→            (int) $this->request->user->id,
 72→            session_id() ?: ''
 73→        );
 74→
 75→        return json([
 76→            'code'    => 0,
 77→            'message' => 'Logged out successfully',
 78→            'data'    => null,
 79→        ], 200);
