  6→use app\exception\ForbiddenException;
  7→use app\exception\NotFoundException;
  8→use app\model\Order;
  9→use app\service\OrderService;
 10→
 11→class OrderController extends BaseController
 12→{
 13→    protected OrderService $orderService;
 14→
 15→    public function __construct()
 16→    {
 17→        $this->orderService = new OrderService();
 18→    }
 19→
 20→    /**
 21→     * GET /api/orders
 22→     */
 23→    public function index()
 24→    {
 25→        $userId  = (int) $this->request->user->id;
 26→        $page    = max(1, (int) $this->request->get('page', 1));
 27→        $perPage = min(100, max(1, (int) $this->request->get('per_page', 15)));
 28→        $role    = $this->request->get('role', '');
 29→        $status  = $this->request->get('status', '');
 30→
 31→        $query = Order::where('organization_id', $this->request->orgId);
 32→
 33→        // Filter by role
 34→        if ($role === 'passenger') {
 35→            $query->where('passenger_id', $userId);
 36→        } elseif ($role === 'driver') {
 37→            $query->where('driver_id', $userId);
 38→        } else {
 39→            $query->where(function ($q) use ($userId) {
 40→                $q->where('passenger_id', $userId)
 41→                  ->whereOr('driver_id', $userId);
 42→            });
 43→        }
 44→
 45→        if ($status !== '') {
 46→            $query->where('status', $status);
 47→        }
 48→
 49→        $query->order('created_at', 'desc');
 50→
 51→        $total    = $query->count();
 52→        $orders   = $query->page($page, $perPage)->select();
 53→        $lastPage = (int) ceil($total / $perPage);
 54→
 55→        return json([
 56→            'code'    => 0,
 57→            'message' => 'OK',
 58→            'data'    => $orders->toArray(),
 59→            'meta'    => [
 60→                'total'     => $total,
 61→                'page'      => $page,
 62→                'per_page'  => $perPage,
 63→                'last_page' => $lastPage,
 64→            ],
 65→        ], 200);
 66→    }
 67→
 68→    /**
 69→     * POST /api/orders
 70→     */
 71→    public function store()
 72→    {
 73→        validate($this->request->post(), 'app\validate\OrderValidate.create');
 74→
 75→        $order = $this->orderService->create(
 76→            $this->request->orgId,
 77→            (int) $this->request->user->id,
 78→            $this->request->post()
 79→        );
 80→
 81→        return json([
 82→            'code'    => 0,
 83→            'message' => 'Order created successfully',
 84→            'data'    => $order->toArray(),
 85→        ], 201);
 86→    }
 87→
 88→    /**
 89→     * GET /api/orders/:id
 90→     */
 91→    public function show($id)
 92→    {
 93→        $order = Order::with(['listing', 'passenger', 'driver'])->find($id);
 94→        if (!$order) {
 95→            throw new NotFoundException('Order not found');
 96→        }
 97→
 98→        $userId = (int) $this->request->user->id;
 99→        $isParty = (int) $order->passenger_id === $userId || (int) $order->driver_id === $userId;
100→        $isAdmin = $this->request->user->isAdmin();
101→
102→        if (!$isParty && !$isAdmin) {
103→            throw new ForbiddenException('You do not have access to this order');
104→        }
105→
106→        $data = $order->toArray();
107→
108→        // Return action verbs for frontend gating.
109→        $data['allowed_transitions'] = $order->getAllowedActions();
110→
111→        // Include cancel_free_until for accepted orders
112→        if ($order->status === 'accepted' && $order->accepted_at) {
113→            $data['cancel_free_until'] = date('Y-m-d\TH:i:s\Z', strtotime($order->accepted_at) + 300);
114→        }
115→
116→        // Listing summary
117→        if ($order->listing) {
118→            $data['listing_summary'] = [
119→                'id'              => $order->listing->id,
120→                'title'           => $order->listing->title,
121→                'pickup_address'  => $order->listing->pickup_address,
122→                'dropoff_address' => $order->listing->dropoff_address,
123→            ];
124→        }
125→
126→        // Passenger/driver info
127→        if ($order->passenger) {
128→            $data['passenger_info'] = [
129→                'id'   => $order->passenger->id,
130→                'name' => $order->passenger->name,
131→            ];
132→        }
133→        if ($order->driver) {
134→            $data['driver_info'] = [
135→                'id'   => $order->driver->id,
136→                'name' => $order->driver->name,
137→            ];
138→        }
139→
140→        return json([
141→            'code'    => 0,
142→            'message' => 'OK',
143→            'data'    => $data,
144→        ], 200);
145→    }
146→
147→    /**
148→     * POST /api/orders/:id/accept
149→     */
150→    public function accept($id)
151→    {
152→        $order = $this->orderService->accept(
153→            (int) $id,
154→            (int) $this->request->user->id
155→        );
156→
157→        return json([
158→            'code'    => 0,
159→            'message' => 'Order accepted',
160→            'data'    => $order->toArray(),
161→        ], 200);
162→    }
163→
164→    /**
165→     * POST /api/orders/:id/start
166→     */
167→    public function start($id)
168→    {
169→        $order = Order::find($id);
170→        if (!$order) {
171→            throw new NotFoundException('Order not found');
172→        }
173→        $this->verifyParty($order);
174→
175→        $order = $this->orderService->start(
176→            (int) $id,
177→            (int) $this->request->user->id
178→        );
179→
180→        return json([
181→            'code'    => 0,
182→            'message' => 'Order started',
183→            'data'    => $order->toArray(),
184→        ], 200);
185→    }
186→
187→    /**
188→     * POST /api/orders/:id/complete
189→     */
190→    public function complete($id)
191→    {
192→        $order = Order::find($id);
193→        if (!$order) {
194→            throw new NotFoundException('Order not found');
195→        }
196→        $this->verifyParty($order);
197→
198→        $order = $this->orderService->complete(
199→            (int) $id,
200→            (int) $this->request->user->id
201→        );
202→
203→        return json([
204→            'code'    => 0,
205→            'message' => 'Order completed',
206→            'data'    => $order->toArray(),
207→        ], 200);
208→    }
209→
210→    /**
211→     * POST /api/orders/:id/cancel
212→     */
213→    public function cancel($id)
214→    {
215→        $order = Order::find($id);
216→        if (!$order) {
217→            throw new NotFoundException('Order not found');
218→        }
219→        $this->verifyParty($order);
220→
221→        $reasonCode = $this->request->post('reason_code');
222→        $reasonText = $this->request->post('reason_text');
223→
224→        // Validate cancel fields if provided
225→        if ($reasonCode !== null || $reasonText !== null) {
226→            validate($this->request->post(), 'app\validate\OrderValidate.cancel');
227→        }
228→
229→        $order = $this->orderService->cancel(
230→            (int) $id,
231→            (int) $this->request->user->id,
232→            $reasonCode,
233→            $reasonText
234→        );
235→
236→        return json([
237→            'code'    => 0,
238→            'message' => 'Order cancelled',
239→            'data'    => $order->toArray(),
240→        ], 200);
241→    }
242→
243→    /**
244→     * POST /api/orders/:id/dispute
245→     */
246→    public function dispute($id)
247→    {
248→        $order = Order::find($id);
249→        if (!$order) {
250→            throw new NotFoundException('Order not found');
251→        }
252→        $this->verifyParty($order);
253→
254→        validate($this->request->post(), 'app\validate\OrderValidate.dispute');
255→
256→        $order = $this->orderService->dispute(
257→            (int) $id,
258→            (int) $this->request->user->id,
259→            $this->request->post('reason')
260→        );
261→
262→        return json([
263→            'code'    => 0,
264→            'message' => 'Dispute filed',
265→            'data'    => $order->toArray(),
266→        ], 200);
267→    }
268→
269→    /**
270→     * POST /api/orders/:id/resolve
271→     */
272→    public function resolve($id)
273→    {
274→        validate($this->request->post(), 'app\validate\OrderValidate.resolve');
275→
276→        $order = $this->orderService->resolve(
277→            (int) $id,
278→            $this->request->post('resolution'),
279→            $this->request->post('outcome')
280→        );
281→
282→        return json([
283→            'code'    => 0,
284→            'message' => 'Order resolved',
285→            'data'    => $order->toArray(),
286→        ], 200);
287→    }
288→
289→    /**
290→     * Verify the current user is a party to the order.
291→     */
292→    private function verifyParty(Order $order): void
293→    {
294→        $userId = (int) $this->request->user->id;
295→        if ((int) $order->passenger_id !== $userId && (int) $order->driver_id !== $userId) {
296→            throw new ForbiddenException('You are not a party to this order');
297→        }
298→    }
299→}
