  1→<?php
  2→declare(strict_types=1);
  3→
  4→namespace app\command;
  5→
  6→use app\model\Listing;
  7→use app\model\Organization;
  8→use app\model\SearchDictionary;
  9→use think\console\Command;
 10→use think\console\Input;
 11→use think\console\Output;
 12→use think\facade\Db;
 13→use think\facade\Log;
 14→
 15→/**
 16→ * Rebuild search dictionary from listing content.
 17→ *
 18→ * For each organization, extracts words from all active listing titles,
 19→ * descriptions, and tags. Words are normalized (lowercase, strip non-alpha,
 20→ * min length 3). Only words with frequency >= 2 are kept. The dictionary
 21→ * table is truncated and rebuilt per org (idempotent full rebuild).
 22→ */
 23→class SearchBuildDictionaryCommand extends Command
 24→{
 25→    protected function configure(): void
 26→    {
 27→        $this->setName('search:build-dictionary')
 28→             ->setDescription('Rebuild search dictionary from listing content');
 29→    }
 30→
 31→    protected function execute(Input $input, Output $output): int
 32→    {
 33→        $organizations = Organization::select();
 34→        $totalWords = 0;
 35→        $orgCount = 0;
 36→
 37→        foreach ($organizations as $org) {
 38→            $orgId = $org->id;
 39→
 40→            // Get all active listings for this org
 41→            $listings = Listing::where('organization_id', $orgId)
 42→                ->where('status', 'active')
 43→                ->select();
 44→
 45→            $wordFrequency = [];
 46→
 47→            foreach ($listings as $listing) {
 48→                $text = implode(' ', array_filter([
 49→                    $listing->title ?? '',
 50→                    $listing->description ?? '',
 51→                    $listing->tags ?? '',
 52→                ]));
 53→
 54→                $words = $this->extractWords($text);
 55→
 56→                foreach ($words as $word) {
 57→                    if (!isset($wordFrequency[$word])) {
 58→                        $wordFrequency[$word] = 0;
 59→                    }
 60→                    $wordFrequency[$word]++;
 61→                }
 62→            }
 63→
 64→            // Filter: keep only words with frequency >= 2
 65→            $wordFrequency = array_filter($wordFrequency, function (int $count): bool {
 66→                return $count >= 2;
 67→            });
 68→
 69→            // Truncate existing dictionary for this org
 70→            SearchDictionary::where('organization_id', $orgId)->delete();
 71→
 72→            // Rebuild
 73→            $insertData = [];
 74→            foreach ($wordFrequency as $word => $frequency) {
 75→                $insertData[] = [
 76→                    'organization_id' => $orgId,
 77→                    'word'            => (string) $word,
 78→                    'frequency'       => $frequency,
 79→                ];
 80→            }
 81→
 82→            // Batch insert in chunks
 83→            foreach (array_chunk($insertData, 500) as $chunk) {
 84→                (new SearchDictionary())->saveAll($chunk);
 85→            }
 86→
 87→            $wordCount = count($wordFrequency);
 88→            $totalWords += $wordCount;
 89→
 90→            if ($wordCount > 0) {
 91→                $orgCount++;
 92→            }
 93→        }
 94→
 95→        Log::info("search:build-dictionary completed: {$totalWords} words for {$orgCount} organizations");
 96→        $output->writeln("Dictionary rebuilt: {$totalWords} words for {$orgCount} organizations.");
 97→
 98→        return 0;
 99→    }
100→
101→    /**
102→     * Extract and normalize words from text.
103→     *
104→     * @param string $text
105→     * @return string[]
106→     */
107→    private function extractWords(string $text): array
108→    {
109→        // Lowercase
110→        $text = mb_strtolower($text, 'UTF-8');
111→
112→        // Strip non-alpha characters (keep spaces)
113→        $text = preg_replace('/[^a-z\s]/u', ' ', $text);
114→
115→        // Split on whitespace
116→        $words = preg_split('/\s+/', $text, -1, PREG_SPLIT_NO_EMPTY);
117→
118→        // Filter minimum length 3
119→        return array_filter($words, function (string $word): bool {
120→            return strlen($word) >= 3;
121→        });
122→    }
123→}
