  1→<?php
  2→declare(strict_types=1);
  3→
  4→namespace app\command;
  5→
  6→use app\model\DataLineage;
  7→use app\model\Order;
  8→use app\model\Organization;
  9→use app\model\Review;
 10→use app\model\User;
 11→use think\console\Command;
 12→use think\console\Input;
 13→use think\console\Output;
 14→use think\facade\Log;
 15→
 16→/**
 17→ * Recompute credibility scores for all reviews.
 18→ *
 19→ * For each organization, loads all reviews with their associated users and
 20→ * orders, then recalculates the credibility_score using the same formula
 21→ * as CredibilityService::compute().
 22→ *
 23→ * Credibility formula:
 24→ *   score = w_age * age_factor
 25→ *         + w_completion * completion_factor
 26→ *         + w_pattern * pattern_factor
 27→ *         + w_timing * timing_factor
 28→ *
 29→ * Weights: age=0.25, completion=0.30, pattern=0.25, timing=0.20
 30→ */
 31→class CredibilityRecomputeCommand extends Command
 32→{
 33→    /** @var float[] */
 34→    private const WEIGHTS = [
 35→        'age'        => 0.25,
 36→        'completion' => 0.30,
 37→        'pattern'    => 0.25,
 38→        'timing'     => 0.20,
 39→    ];
 40→
 41→    protected function configure(): void
 42→    {
 43→        $this->setName('credibility:recompute')
 44→             ->setDescription('Recompute credibility scores for all reviews');
 45→    }
 46→
 47→    protected function execute(Input $input, Output $output): int
 48→    {
 49→        $runId = $this->generateUuid();
 50→        $totalReviews = 0;
 51→
 52→        $organizations = Organization::select();
 53→
 54→        foreach ($organizations as $org) {
 55→            $orgId = $org->id;
 56→
 57→            $reviews = Review::where('organization_id', $orgId)->select();
 58→
 59→            foreach ($reviews as $review) {
 60→                $user = User::find($review->user_id);
 61→                if (!$user) {
 62→                    continue;
 63→                }
 64→
 65→                $score = $this->computeCredibility($review, $user, $orgId);
 66→                $review->credibility_score = round($score, 4);
 67→                $review->save();
 68→
 69→                $totalReviews++;
 70→            }
 71→
 72→            // Record lineage
 73→            DataLineage::create([
 74→                'organization_id' => $orgId,
 75→                'job_name'        => 'credibility:recompute',
 76→                'run_id'          => $runId,
 77→                'step'            => 'credibility_recompute',
 78→                'input_count'     => count($reviews),
 79→                'output_count'    => count($reviews),
 80→                'removed_count'   => 0,
 81→                'executed_at'     => date('Y-m-d H:i:s'),
 82→            ]);
 83→        }
 84→
 85→        Log::info("credibility:recompute completed: recomputed {$totalReviews} reviews (run_id={$runId})");
 86→        $output->writeln("Recomputed credibility for {$totalReviews} reviews.");
 87→
 88→        return 0;
 89→    }
 90→
 91→    /**
 92→     * Compute credibility score for a single review.
 93→     */
 94→    private function computeCredibility(Review $review, User $user, int $orgId): float
 95→    {
 96→        // Age factor: account age < 14 days => 0.5, otherwise 1.0
 97→        $accountAgeDays = (time() - strtotime($user->created_at)) / 86400;
 98→        $ageFactor = $accountAgeDays < 14 ? 0.5 : 1.0;
 99→
100→        // Completion factor: ratio of completed orders to total orders
101→        $totalOrders = Order::where('organization_id', $orgId)
102→            ->where(function ($query) use ($user) {
103→                $query->where('passenger_id', $user->id)
104→                    ->whereOr('driver_id', $user->id);
105→            })
106→            ->count();
107→        $completedOrders = Order::where('organization_id', $orgId)
108→            ->where(function ($query) use ($user) {
109→                $query->where('passenger_id', $user->id)
110→                    ->whereOr('driver_id', $user->id);
111→            })
112→            ->where('status', 'completed')
113→            ->count();
114→        $completionFactor = $totalOrders > 0 ? $completedOrders / $totalOrders : 0.0;
115→
116→        // Pattern factor: penalize burst of 5-star reviews
117→        $recentFiveStarCount = Review::where('user_id', $user->id)
118→            ->where('organization_id', $orgId)
119→            ->where('rating', 5)
120→            ->where('created_at', '>=', date('Y-m-d H:i:s', strtotime('-24 hours')))
121→            ->count();
122→        $patternFactor = $recentFiveStarCount >= 3 ? 0.5 : 1.0;
123→
124→        // Timing factor: review within 5 minutes of order completion is suspicious
125→        $order = Order::find($review->order_id);
126→        $timingFactor = 1.0;
127→        if ($order && $order->completed_at) {
128→            $completionTime = strtotime($order->completed_at);
129→            $reviewTime = strtotime($review->created_at);
130→            $diffMinutes = ($reviewTime - $completionTime) / 60;
131→            if ($diffMinutes >= 0 && $diffMinutes <= 5) {
132→                $timingFactor = 0.5;
133→            }
134→        }
135→
136→        // Weighted sum, clamped to [0, 1]
137→        $score = self::WEIGHTS['age'] * $ageFactor
138→               + self::WEIGHTS['completion'] * $completionFactor
139→               + self::WEIGHTS['pattern'] * $patternFactor
140→               + self::WEIGHTS['timing'] * $timingFactor;
141→
142→        return max(0.0, min(1.0, $score));
143→    }
144→
145→    private function generateUuid(): string
146→    {
147→        $data = random_bytes(16);
148→        $data[6] = chr(ord($data[6]) & 0x0f | 0x40);
149→        $data[8] = chr(ord($data[8]) & 0x3f | 0x80);
150→
151→        return vsprintf('%s%s-%s-%s-%s-%s%s%s', str_split(bin2hex($data), 4));
152→    }
153→}
