 4→namespace app\command;
 5→
 6→use app\model\AuditLog;
 7→use app\model\Listing;
 8→use app\model\Order;
 9→use think\console\Command;
10→use think\console\Input;
11→use think\console\Output;
12→use think\facade\Db;
13→use think\facade\Log;
14→
15→/**
16→ * Auto-expire pending_match orders older than 30 minutes.
17→ *
18→ * This command is designed to run every minute via cron. It is fully
19→ * idempotent: orders already expired will not be touched because the
20→ * WHERE clause filters on status = 'pending_match'.
21→ */
22→class OrderExpireCommand extends Command
23→{
24→    protected function configure(): void
25→    {
26→        $this->setName('order:expire')
27→             ->setDescription('Auto-expire pending_match orders older than 30 minutes');
28→    }
29→
30→    protected function execute(Input $input, Output $output): int
31→    {
32→        $cutoff = date('Y-m-d H:i:s', strtotime('-30 minutes'));
33→
34→        $pendingOrders = Order::where('status', 'pending_match')
35→            ->where('created_at', '<', $cutoff)
36→            ->select();
37→
38→        $expiredCount = 0;
39→
40→        Db::startTrans();
41→        try {
42→            foreach ($pendingOrders as $order) {
43→                // Expire the order
44→                $order->status = 'expired';
45→                $order->expires_at = date('Y-m-d H:i:s');
46→                $order->save();
47→
48→                // Restore the listing to active status so it can be matched again
49→                $listing = Listing::find($order->listing_id);
50→                if ($listing && $listing->status === 'matched') {
51→                    $listing->status = 'active';
52→                    $listing->save();
53→                }
54→
55→                // Create audit log entry
56→                AuditLog::create([
57→                    'organization_id' => $order->organization_id,
58→                    'user_id'         => $order->passenger_id,
59→                    'action'          => 'order.auto_expired',
60→                    'resource_type'   => 'order',
61→                    'resource_id'     => $order->id,
62→                    'old_value'       => json_encode(['status' => 'pending_match']),
63→                    'new_value'       => json_encode(['status' => 'expired']),
64→                    'ip_address'      => '127.0.0.1',
65→                    'created_at'      => date('Y-m-d H:i:s'),
66→                ]);
67→
68→                $expiredCount++;
69→            }
70→
71→            Db::commit();
72→        } catch (\Throwable $e) {
73→            Db::rollback();
74→            Log::error('order:expire failed: ' . $e->getMessage());
75→            $output->writeln("<error>Error: {$e->getMessage()}</error>");
76→            return 1;
77→        }
78→
79→        Log::info("order:expire completed: expired {$expiredCount} orders");
80→        $output->writeln("Expired {$expiredCount} orders.");
81→
82→        return 0;
83→    }
84→}
