  1→<?php
  2→declare(strict_types=1);
  3→
  4→namespace app\service;
  5→
  6→use app\exception\AuthException;
  7→use app\exception\BusinessException;
  8→use app\exception\NotFoundException;
  9→use app\exception\ValidationException;
 10→use app\model\Organization;
 11→use app\model\Role;
 12→use app\model\User;
 13→use app\model\UserSession;
 14→use think\facade\Session;
 15→
 16→class AuthService
 17→{
 18→    /**
 19→     * Register a new user within an organization.
 20→     */
 21→    public function register(array $data): User
 22→    {
 23→        $org = Organization::where('code', $data['organization_code'])->find();
 24→        if (!$org) {
 25→            throw new NotFoundException('Organization not found', 40401);
 26→        }
 27→
 28→        $existing = User::where('email', $data['email'])
 29→            ->where('organization_id', $org->id)
 30→            ->find();
 31→        if ($existing) {
 32→            throw new BusinessException('Email already registered in this organization', 40901, 409);
 33→        }
 34→
 35→        $user = new User();
 36→        $user->name            = $data['name'];
 37→        $user->email           = $data['email'];
 38→        $user->password_hash   = password_hash($data['password'], PASSWORD_BCRYPT);
 39→        $user->organization_id = $org->id;
 40→        $user->status          = 'active';
 41→        $user->save();
 42→
 43→        // Assign default 'user' role
 44→        $role = Role::where('slug', 'user')
 45→            ->where('organization_id', $org->id)
 46→            ->find();
 47→        if ($role) {
 48→            $user->roles()->attach($role->id);
 49→        }
 50→
 51→        // Create initial session record
 52→        $session = new UserSession();
 53→        $session->user_id   = $user->id;
 54→        $session->session_id = session_id() ?: bin2hex(random_bytes(20));
 55→        $session->ip_address = request()->ip();
 56→        $session->user_agent = request()->header('User-Agent', '');
 57→        $session->expires_at = date('Y-m-d\TH:i:s\Z', strtotime('+24 hours'));
 58→        $session->save();
 59→
 60→        return $user;
 61→    }
 62→
 63→    /**
 64→     * Authenticate a user by email and password.
 65→     */
 66→    public function login(string $email, string $password, string $organizationCode, string $ip, string $userAgent): array
 67→    {
 68→        $org = Organization::where('code', $organizationCode)->find();
 69→        if (!$org) {
 70→            throw new AuthException('Invalid credentials', 40101);
 71→        }
 72→
 73→        $user = User::where('email', $email)
 74→            ->where('organization_id', $org->id)
 75→            ->find();
 76→        if (!$user) {
 77→            throw new AuthException('Invalid credentials', 40101);
 78→        }
 79→
 80→        if (!password_verify($password, $user->password_hash)) {
 81→            throw new AuthException('Invalid credentials', 40101);
 82→        }
 83→
 84→        if ($user->status !== 'active') {
 85→            throw new AuthException('Account is disabled', 40102);
 86→        }
 87→
 88→        $expiresAt = date('Y-m-d\TH:i:s\Z', strtotime('+24 hours'));
 89→
 90→        // Create session record
 91→        $session = new UserSession();
 92→        $session->user_id   = $user->id;
 93→        $session->session_id = session_id() ?: bin2hex(random_bytes(20));
 94→        $session->ip_address = $ip;
 95→        $session->user_agent = $userAgent;
 96→        $session->expires_at = $expiresAt;
 97→        $session->save();
 98→
 99→        // Start PHP session
100→        Session::set('user_id', $user->id);
101→
102→        return [
103→            'user'               => $user,
104→            'roles'              => array_map(static function ($role): string {
105→                return (string) ($role['slug'] ?? '');
106→            }, $user->roles()->select()->toArray()),
107→            'session_expires_at' => $expiresAt,
108→        ];
109→    }
110→
111→    /**
112→     * Log out a user by destroying their session.
113→     */
114→    public function logout(int $userId, string $sessionId): void
115→    {
116→        UserSession::where('user_id', $userId)
117→            ->where('session_id', $sessionId)
118→            ->delete();
119→
120→        Session::clear();
121→    }
122→
123→    /**
124→     * Get the current authenticated user with roles.
125→     */
126→    public function getCurrentUser(int $userId): User
127→    {
128→        $user = User::with(['roles'])->find($userId);
129→        if (!$user) {
130→            throw new NotFoundException('User not found', 40401);
131→        }
132→        return $user;
133→    }
134→}
