  1→<?php
  2→declare(strict_types=1);
  3→
  4→namespace app\controller;
  5→
  6→use app\exception\ValidationException;
  7→use app\model\ModerationQueue;
  8→use app\service\ModerationService;
  9→
 10→class ModerationController extends BaseController
 11→{
 12→    protected ModerationService $moderationService;
 13→
 14→    public function __construct()
 15→    {
 16→        $this->moderationService = new ModerationService();
 17→    }
 18→
 19→    /**
 20→     * GET /api/moderation
 21→     */
 22→    public function index()
 23→    {
 24→        $page    = max(1, (int) $this->request->get('page', 1));
 25→        $perPage = min(100, max(1, (int) $this->request->get('per_page', 15)));
 26→        $type    = $this->request->get('type', '');
 27→        $reason  = $this->request->get('flag_reason', '');
 28→        $sort    = $this->request->get('sort', 'newest');
 29→
 30→        $query = ModerationQueue::where('organization_id', $this->request->orgId);
 31→
 32→        if ($type !== '') {
 33→            $query->where('item_type', $type);
 34→        }
 35→        if ($reason !== '') {
 36→            $query->where('flag_reason', 'like', '%' . $reason . '%');
 37→        }
 38→
 39→        switch ($sort) {
 40→            case 'oldest':
 41→                $query->order('created_at', 'asc');
 42→                break;
 43→            case 'credibility_asc':
 44→                $query->order('credibility_score', 'asc');
 45→                break;
 46→            case 'credibility_desc':
 47→                $query->order('credibility_score', 'desc');
 48→                break;
 49→            case 'newest':
 50→            default:
 51→                $query->order('created_at', 'desc');
 52→                break;
 53→        }
 54→
 55→        $total   = $query->count();
 56→        $items   = $query->page($page, $perPage)->select();
 57→        $lastPage = (int) ceil($total / $perPage);
 58→
 59→        // Enrich with content preview and user info
 60→        $enriched = [];
 61→        foreach ($items as $item) {
 62→            $data = $item->toArray();
 63→
 64→            // Load content preview based on item type
 65→            if ($item->item_type === 'review') {
 66→                $review = \app\model\Review::with(['user'])->find($item->item_id);
 67→                if ($review) {
 68→                    $data['content_preview'] = mb_substr($review->text ?? '', 0, 200);
 69→                    $data['user_info']       = $review->user ? [
 70→                        'id'   => $review->user->id,
 71→                        'name' => $review->user->name,
 72→                    ] : null;
 73→                }
 74→            } elseif ($item->item_type === 'listing') {
 75→                $listing = \app\model\Listing::with(['user'])->find($item->item_id);
 76→                if ($listing) {
 77→                    $data['content_preview'] = mb_substr($listing->title ?? '', 0, 200);
 78→                    $data['user_info']       = $listing->user ? [
 79→                        'id'   => $listing->user->id,
 80→                        'name' => $listing->user->name,
 81→                    ] : null;
 82→                }
 83→            }
 84→
 85→            $enriched[] = $data;
 86→        }
 87→
 88→        return json([
 89→            'code'    => 0,
 90→            'message' => 'OK',
 91→            'data'    => $enriched,
 92→            'meta'    => [
 93→                'total'     => $total,
 94→                'page'      => $page,
 95→                'per_page'  => $perPage,
 96→                'last_page' => $lastPage,
 97→            ],
 98→        ], 200);
