  2→ * order-detail.js - Order Detail Page
  3→ * Full lifecycle UI with status header, progress bar, parties, actions, disputes, resolution.
  4→ */
  5→var OrderDetailPage = (function () {
  6→    'use strict';
  7→
  8→    var LIFECYCLE_STEPS = [
  9→        { key: 'pending_match', label: 'Pending Match' },
 10→        { key: 'accepted', label: 'Accepted' },
 11→        { key: 'in_progress', label: 'In Progress' },
 12→        { key: 'completed', label: 'Completed' }
 13→    ];
 14→
 15→    var CANCEL_REASONS = [
 16→        { value: 'DRIVER_UNAVAILABLE', label: 'Driver Unavailable' },
 17→        { value: 'PASSENGER_CHANGED_PLANS', label: 'Passenger Changed Plans' },
 18→        { value: 'VEHICLE_ISSUE', label: 'Vehicle Issue' },
 19→        { value: 'SCHEDULE_CONFLICT', label: 'Schedule Conflict' },
 20→        { value: 'OTHER', label: 'Other' }
 21→    ];
 22→
 23→    var RESOLUTION_OUTCOMES = [
 24→        { value: 'passenger_favor', label: 'Passenger Favor' },
 25→        { value: 'driver_favor', label: 'Driver Favor' },
 26→        { value: 'mutual', label: 'Mutual Resolution' },
 27→        { value: 'dismissed', label: 'Dismissed' }
 28→    ];
 29→
 30→    var STATUS_COLORS = {
 31→        pending_match: '#1E9FFF',
 32→        accepted: '#FFB800',
 33→        in_progress: '#FF6600',
 34→        completed: '#16b777',
 35→        canceled: '#999',
 36→        expired: '#999',
 37→        disputed: '#FF5722',
 38→        resolved: '#7c4dff'
 39→    };
 40→
 41→    var state = {
 42→        order: null,
 43→        orderId: null,
 44→        loading: false,
 45→        error: null,
 46→        actionLoading: false
 47→    };
 48→
 49→    function currentUserId() {
 50→        var u = RCAuth.getUser();
 51→        return u ? u.id : null;
 52→    }
 53→
 54→    function isParty() {
 55→        if (!state.order) return false;
 56→        var uid = currentUserId();
 57→        return state.order.passenger_id === uid || state.order.driver_id === uid;
 58→    }
 59→
 60→    function userRole() {
 61→        if (!state.order) return null;
 62→        var uid = currentUserId();
 63→        if (state.order.passenger_id === uid) return 'passenger';
 64→        if (state.order.driver_id === uid) return 'driver';
 65→        return null;
 66→    }
 67→
 68→    function relevantTimestamp(order) {
 69→        var map = {
 70→            pending_match: order.created_at,
 71→            accepted: order.accepted_at,
 72→            in_progress: order.started_at,
 73→            completed: order.completed_at,
 74→            canceled: order.canceled_at,
 75→            expired: order.expires_at,
 76→            disputed: order.disputed_at,
 77→            resolved: order.resolved_at
 78→        };
 79→        return map[order.status] || order.created_at;
 80→    }
 81→
 82→    function stepIndex(status) {
 83→        for (var i = 0; i < LIFECYCLE_STEPS.length; i++) {
 84→            if (LIFECYCLE_STEPS[i].key === status) return i;
 85→        }
 86→        return -1;
 87→    }
 88→
 89→    function isTerminal(status) {
 90→        return ['canceled', 'expired', 'disputed', 'resolved'].indexOf(status) !== -1;
 91→    }
 92→
 93→    function isCancelFree(order) {
 94→        if (order.status === 'pending_match') return true;
 95→        if (order.status === 'accepted' && order.cancel_free_until) {
 96→            return new Date(order.cancel_free_until) > new Date();
 97→        }
 98→        return false;
 99→    }
100→
101→    function isWithin72h(completedAt) {
102→        if (!completedAt) return false;
103→        var completed = new Date(completedAt);
104→        var cutoff = new Date(completed.getTime() + 72 * 60 * 60 * 1000);
105→        return new Date() < cutoff;
106→    }
107→
108→    function hasTransition(name) {
109→        if (!state.order || !state.order.allowed_transitions) return false;
110→        return state.order.allowed_transitions.indexOf(name) !== -1;
111→    }
112→
113→    // ---------------------------------------------------------------
114→    // Render helpers
115→    // ---------------------------------------------------------------
116→
117→    function renderStatusHeader(order) {
118→        var color = STATUS_COLORS[order.status] || '#999';
119→        var ts = relevantTimestamp(order);
120→        var label = order.status.replace(/_/g, ' ').replace(/\b\w/g, function (c) {
121→            return c.toUpperCase();
122→        });
123→        return '<div style="background:' + color + ';color:#fff;padding:20px 24px;border-radius:4px;margin-bottom:20px;">' +
124→            '<div style="display:flex;justify-content:space-between;align-items:center;">' +
125→            '<span style="font-size:22px;font-weight:600;">' + RCUtil.escapeHtml(label) + '</span>' +
126→            '<span style="font-size:14px;opacity:0.9;">' + (ts ? RCUtil.formatDateTime(ts) : '') + '</span>' +
127→            '</div></div>';
128→    }
129→
130→    function renderProgressBar(order) {
131→        var current = stepIndex(order.status);
132→        var terminal = isTerminal(order.status);
133→
134→        var html = '<div style="display:flex;align-items:center;margin-bottom:24px;padding:0 8px;">';
135→        for (var i = 0; i < LIFECYCLE_STEPS.length; i++) {
136→            var step = LIFECYCLE_STEPS[i];
137→            var filled = (!terminal && i <= current) || (terminal && i <= current);
138→            var isCurrent = !terminal && i === current;
139→            var bg, fg;
140→            if (terminal && current === -1) {
141→                bg = '#e0e0e0'; fg = '#999';
142→            } else if (i < current || (i === current && !terminal)) {
143→                bg = '#16b777'; fg = '#fff';
144→            } else if (terminal && i === current) {
145→                bg = STATUS_COLORS[order.status] || '#999'; fg = '#fff';
146→            } else {
147→                bg = '#e0e0e0'; fg = '#999';
148→            }
149→
150→            html += '<div style="flex:1;text-align:center;">' +
151→                '<div style="width:36px;height:36px;border-radius:50%;background:' + bg +
152→                ';color:' + fg + ';display:inline-flex;align-items:center;justify-content:center;font-weight:600;font-size:14px;">' +
153→                (i + 1) + '</div>' +
154→                '<div style="font-size:12px;margin-top:4px;color:' + (isCurrent ? '#333' : '#999') + ';">' +
155→                RCUtil.escapeHtml(step.label) + '</div></div>';
156→            if (i < LIFECYCLE_STEPS.length - 1) {
157→                var lineColor = (i < current) ? '#16b777' : '#e0e0e0';
158→                html += '<div style="flex:1;height:3px;background:' + lineColor + ';margin:0 4px;border-radius:2px;align-self:center;margin-bottom:18px;"></div>';
159→            }
160→        }
161→
162→        if (terminal) {
163→            var tLabel = order.status.replace(/_/g, ' ').replace(/\b\w/g, function (c) { return c.toUpperCase(); });
164→            html += '<div style="flex:0;text-align:center;margin-left:12px;">' +
165→                '<div style="width:36px;height:36px;border-radius:50%;background:' +
166→                (STATUS_COLORS[order.status] || '#999') + ';color:#fff;display:inline-flex;align-items:center;justify-content:center;">' +
167→                '<i class="layui-icon layui-icon-close"></i></div>' +
168→                '<div style="font-size:12px;margin-top:4px;color:#999;">' + RCUtil.escapeHtml(tLabel) + '</div></div>';
169→        }
170→
171→        html += '</div>';
172→        return html;
173→    }
174→
175→    function renderPartiesCard(order) {
176→        var pName = order.passenger_info ? RCUtil.escapeHtml(order.passenger_info.name) : 'Passenger #' + order.passenger_id;
177→        var dName = order.driver_info ? RCUtil.escapeHtml(order.driver_info.name) : 'Driver #' + order.driver_id;
178→        var role = userRole();
179→        var roleLabel = role ? 'You are the <strong>' + role + '</strong>' : '';
180→
181→        return '<div class="layui-card" style="margin-bottom:16px;">' +
182→            '<div class="layui-card-header">Parties</div>' +
