421→    // ---------------------------------------------------------------
422→
423→    function bindEvents(container) {
424→        // Cancel reason code toggle
425→        var reasonSelect = container.querySelector('#rc-cancel-reason-code');
426→        if (reasonSelect) {
427→            reasonSelect.addEventListener('change', function () {
428→                var textGroup = container.querySelector('#rc-cancel-text-group');
429→                if (textGroup) {
430→                    textGroup.style.display = this.value === 'OTHER' ? '' : 'none';
431→                }
432→            });
433→        }
434→
435→        // Dispute character counter
436→        var disputeArea = container.querySelector('#rc-dispute-reason');
437→        if (disputeArea) {
438→            disputeArea.addEventListener('input', function () {
439→                var counter = container.querySelector('#rc-dispute-count');
440→                if (counter) counter.textContent = this.value.length;
441→            });
442→        }
443→
444→        // Leave review
445→        var reviewBtn = container.querySelector('.rc-leave-review-btn');
446→        if (reviewBtn) {
447→            reviewBtn.addEventListener('click', function () {
448→                RCRouter.navigate('#/orders/' + state.orderId + '/review');
449→            });
450→        }
451→
452→        // Action buttons
453→        container.querySelectorAll('.rc-action-btn').forEach(function (btn) {
454→            btn.addEventListener('click', function () {
455→                var action = this.getAttribute('data-action');
456→                handleAction(action, container);
457→            });
458→        });
459→
460→        // Back link
461→        var backLink = container.querySelector('a[href="#/orders"]');
462→        if (backLink) {
463→            backLink.addEventListener('click', function (e) {
464→                e.preventDefault();
465→                RCRouter.navigate('#/orders');
466→            });
467→        }
468→    }
