470→    function setActionLoading(container, loading) {
471→        state.actionLoading = loading;
472→        container.querySelectorAll('.rc-action-btn').forEach(function (btn) {
473→            btn.disabled = loading;
474→            if (loading) {
475→                btn.classList.add('layui-btn-disabled');
476→            } else {
477→                btn.classList.remove('layui-btn-disabled');
478→            }
479→        });
480→    }
481→
482→    function handleAction(action, container) {
483→        if (state.actionLoading) return;
484→
485→        switch (action) {
486→            case 'accept':
487→                layui.layer.confirm('Accept this match and confirm the ride?', { title: 'Confirm Accept' }, function (idx) {
488→                    layui.layer.close(idx);
489→                    executeAction(function () { return RCApi.acceptOrder(state.orderId); }, container);
490→                });
491→                break;
492→
493→            case 'start':
494→                layui.layer.confirm('Start this trip now?', { title: 'Confirm Start' }, function (idx) {
495→                    layui.layer.close(idx);
496→                    executeAction(function () { return RCApi.startOrder(state.orderId); }, container);
497→                });
498→                break;
499→
500→            case 'complete':
501→                layui.layer.confirm('Mark this trip as completed?', { title: 'Confirm Complete' }, function (idx) {
502→                    layui.layer.close(idx);
503→                    executeAction(function () { return RCApi.completeOrder(state.orderId); }, container);
504→                });
505→                break;
506→
507→            case 'cancel-free':
508→                layui.layer.confirm('Cancel this order? This cancellation is free of charge.', { title: 'Confirm Cancel' }, function (idx) {
509→                    layui.layer.close(idx);
510→                    executeAction(function () { return RCApi.cancelOrder(state.orderId, {}); }, container);
511→                });
512→                break;
513→
514→            case 'cancel-with-reason':
515→                handleCancelWithReason(container);
516→                break;
517→
518→            case 'dispute':
519→                handleDispute(container);
520→                break;
521→
522→            case 'resolve':
523→                handleResolve(container);
524→                break;
525→        }
526→    }
527→
528→    function handleCancelWithReason(container) {
529→        var codeEl = container.querySelector('#rc-cancel-reason-code');
530→        var textEl = container.querySelector('#rc-cancel-reason-text');
531→        var code = codeEl ? codeEl.value : '';
532→        var text = textEl ? textEl.value.trim() : '';
533→
534→        if (!code) {
535→            layui.layer.msg('Please select a cancellation reason.', { icon: 0 });
536→            return;
537→        }
538→        if (code === 'OTHER' && !text) {
539→            layui.layer.msg('Please provide details for your cancellation reason.', { icon: 0 });
540→            return;
541→        }
542→
543→        layui.layer.confirm('Cancel this order?', { title: 'Confirm Cancel' }, function (idx) {
544→            layui.layer.close(idx);
545→            executeAction(function () {
546→                return RCApi.cancelOrder(state.orderId, { reason_code: code, reason_text: text });
547→            }, container);
548→        });
549→    }
550→
551→    function handleDispute(container) {
552→        var reasonEl = container.querySelector('#rc-dispute-reason');
553→        var reason = reasonEl ? reasonEl.value.trim() : '';
554→        if (!reason) {
555→            layui.layer.msg('Please describe the dispute reason.', { icon: 0 });
556→            return;
557→        }
558→        if (reason.length > 1000) {
559→            layui.layer.msg('Dispute reason cannot exceed 1000 characters.', { icon: 0 });
560→            return;
561→        }
562→
563→        layui.layer.confirm('Open a dispute for this order? This will notify the other party and an admin.', { title: 'Confirm Dispute' }, function (idx) {
564→            layui.layer.close(idx);
565→            executeAction(function () {
566→                return RCApi.disputeOrder(state.orderId, { reason: reason });
567→            }, container);
568→        });
569→    }
570→
571→    function handleResolve(container) {
572→        var outcomeEl = container.querySelector('#rc-resolve-outcome');
573→        var textEl = container.querySelector('#rc-resolve-text');
574→        var outcome = outcomeEl ? outcomeEl.value : '';
575→        var resolution = textEl ? textEl.value.trim() : '';
576→
577→        if (!outcome) {
578→            layui.layer.msg('Please select a resolution outcome.', { icon: 0 });
579→            return;
580→        }
581→        if (!resolution) {
582→            layui.layer.msg('Please provide resolution notes.', { icon: 0 });
583→            return;
584→        }
585→        if (resolution.length > 2000) {
586→            layui.layer.msg('Resolution notes cannot exceed 2000 characters.', { icon: 0 });
587→            return;
588→        }
589→
590→        layui.layer.confirm('Resolve this dispute with outcome: ' + outcome.replace(/_/g, ' ') + '?', { title: 'Confirm Resolution' }, function (idx) {
591→            layui.layer.close(idx);
592→            executeAction(function () {
593→                return RCApi.resolveOrder(state.orderId, { outcome: outcome, resolution: resolution });
594→            }, container);
595→        });
596→    }
597→
598→    function executeAction(apiCall, container) {
599→        setActionLoading(container, true);
600→        apiCall().then(function (envelope) {
601→            setActionLoading(container, false);
602→            layui.layer.msg(envelope.message || 'Success', { icon: 1 });
603→            loadOrder(container);
604→        }).catch(function (err) {
605→            setActionLoading(container, false);
606→            var msg = (err && err.message) ? err.message : 'Action failed';
607→            layui.layer.msg(msg, { icon: 2 });
608→        });
609→    }
610→
611→    // ---------------------------------------------------------------
612→    // Data loading
613→    // ---------------------------------------------------------------
614→
615→    function loadOrder(container) {
616→        state.loading = true;
617→        state.error = null;
618→        renderPage(container);
619→
620→        RCApi.getOrder(state.orderId).then(function (envelope) {
621→            state.loading = false;
622→            state.order = envelope.data;
623→            renderPage(container);
624→            bindEvents(container);
625→        }).catch(function (err) {
626→            state.loading = false;
627→            state.error = (err && err.message) ? err.message : 'Failed to load order';
628→            renderPage(container);
629→            bindEvents(container);
630→        });
631→    }
632→
633→    return {
634→        render: function (container, params) {
635→            state.orderId = params && params.id ? params.id : null;
636→            state.order = null;
637→            state.error = null;
638→            if (!state.orderId) {
639→                state.error = 'No order ID provided';
640→                renderPage(container);
641→                return;
642→            }
643→            loadOrder(container);
644→        }
645→    };
646→})();
