 14→class OrderService
 15→{
 16→    protected AuditService $auditService;
 17→
 18→    public function __construct()
 19→    {
 20→        $this->auditService = new AuditService();
 21→    }
 22→
 23→    /**
 24→     * Create a new order for a listing (driver accepts a ride request).
 25→     *
 26→     * When a driver accepts a listing, the order is created directly in
 27→     * 'accepted' status per the prompt's "driver accepts request" semantics.
 28→     */
 29→    public function create(int $orgId, int $driverId, array $data): Order
 30→    {
 31→        $listingId = (int) $data['listing_id'];
 32→
 33→        $listing = Listing::where('id', $listingId)
 34→            ->where('organization_id', $orgId)
 35→            ->find();
 36→
 37→        if (!$listing) {
 38→            throw new NotFoundException('Listing not found');
 39→        }
 40→
 41→        if ($listing->status !== 'active') {
 42→            throw new BusinessException('Listing is not active', 40901, 409);
 43→        }
 44→
 45→        if ((int) $listing->user_id === $driverId) {
 46→            throw new BusinessException('Driver cannot be the listing owner', 40901, 409);
 47→        }
 48→
 49→        // Check for existing pending/active order on this listing
 50→        $existingOrder = Order::where('listing_id', $listingId)
 51→            ->whereIn('status', ['pending_match', 'accepted', 'in_progress'])
 52→            ->find();
 53→
 54→        if ($existingOrder) {
 55→            throw new BusinessException('An active order already exists for this listing', 40901, 409);
 56→        }
 57→
 58→        $now = date('Y-m-d\TH:i:s\Z');
 59→
 60→        $order = new Order();
 61→        $order->organization_id = $orgId;
 62→        $order->listing_id     = $listingId;
 63→        $order->driver_id      = $driverId;
 64→        $order->passenger_id   = (int) $listing->user_id;
 65→        $order->status         = 'accepted';
 66→        $order->accepted_at    = $now;
 67→        $order->driver_notes   = $data['driver_notes'] ?? '';
 68→        $order->save();
 69→
 70→        // Update listing status
 71→        $listing->status = 'matched';
 72→        $listing->save();
 73→
 74→        // Record audit log
 75→        $this->auditService->log(
 76→            $orgId,
 77→            $driverId,
 78→            'order.create',
 79→            'order',
 80→            $order->id,
 81→            null,
 82→            ['status' => 'accepted', 'listing_id' => $listingId]
 83→        );
 84→
 85→        return $order;
 86→    }
