 88→    /**
 89→     * Accept a pending order (passenger/listing owner only).
 90→     */
 91→    public function accept(int $orderId, int $userId): Order
 92→    {
 93→        $order = $this->findOrderOrFail($orderId);
 94→
 95→        if ((int) $order->passenger_id !== $userId) {
 96→            throw new ForbiddenException('Only the passenger (listing owner) can accept this order');
 97→        }
 98→
 99→        if ($order->status !== 'pending_match') {
100→            throw new BusinessException(
101→                'Order must be in pending_match status to accept',
102→                40901,
103→                409
104→            );
105→        }
106→
107→        $oldStatus = $order->status;
108→        $order->status      = 'accepted';
109→        $order->accepted_at = date('Y-m-d\TH:i:s\Z');
110→        $order->save();
111→
112→        $this->auditService->log(
113→            (int) $order->organization_id,
114→            $userId,
115→            'order.accept',
116→            'order',
117→            $order->id,
118→            ['status' => $oldStatus],
119→            ['status' => 'accepted']
120→        );
121→
122→        return $order;
123→    }
