125→    /**
126→     * Start an accepted order (must be party).
127→     */
128→    public function start(int $orderId, int $userId): Order
129→    {
130→        $order = $this->findOrderOrFail($orderId);
131→        $this->verifyParty($order, $userId);
132→
133→        if ($order->status !== 'accepted') {
134→            throw new BusinessException(
135→                'Order must be in accepted status to start',
136→                40901,
137→                409
138→            );
139→        }
140→
141→        $oldStatus = $order->status;
142→        $order->status     = 'in_progress';
143→        $order->started_at = date('Y-m-d\TH:i:s\Z');
144→        $order->save();
145→
146→        // Update listing status
147→        $listing = Listing::find($order->listing_id);
148→        if ($listing) {
149→            $listing->status = 'in_progress';
150→            $listing->save();
151→        }
152→
153→        $this->auditService->log(
154→            (int) $order->organization_id,
155→            $userId,
156→            'order.start',
157→            'order',
158→            $order->id,
159→            ['status' => $oldStatus],
160→            ['status' => 'in_progress']
161→        );
162→
163→        return $order;
164→    }
165→
166→    /**
167→     * Complete an in-progress order (must be party).
168→     */
169→    public function complete(int $orderId, int $userId): Order
170→    {
171→        $order = $this->findOrderOrFail($orderId);
172→        $this->verifyParty($order, $userId);
173→
174→        if ($order->status !== 'in_progress') {
175→            throw new BusinessException(
176→                'Order must be in progress to complete',
177→                40901,
178→                409
179→            );
180→        }
181→
182→        $oldStatus = $order->status;
183→        $order->status       = 'completed';
184→        $order->completed_at = date('Y-m-d\TH:i:s\Z');
185→        $order->save();
186→
187→        // Update listing status
188→        $listing = Listing::find($order->listing_id);
189→        if ($listing) {
190→            $listing->status = 'completed';
191→            $listing->save();
192→        }
193→
194→        $this->auditService->log(
195→            (int) $order->organization_id,
196→            $userId,
197→            'order.complete',
198→            'order',
199→            $order->id,
200→            ['status' => $oldStatus],
201→            ['status' => 'completed']
202→        );
203→
204→        return $order;
205→    }
206→
207→    /**
208→     * Cancel an order with strict business rules.
209→     */
210→    public function cancel(int $orderId, int $userId, ?string $reasonCode, ?string $reasonText): Order
211→    {
212→        $order = $this->findOrderOrFail($orderId);
213→        $this->verifyParty($order, $userId);
214→
215→        // Rule 2: Cannot cancel in_progress
216→        if ($order->status === 'in_progress') {
217→            throw new BusinessException(
218→                'Cancellation is not allowed once a trip is in progress.',
219→                40901,
220→                409
221→            );
222→        }
223→
224→        // Must be in a cancellable state
225→        if (!in_array($order->status, ['pending_match', 'accepted'])) {
226→            throw new BusinessException(
227→                'Order cannot be cancelled in its current status',
228→                40901,
229→                409
230→            );
231→        }
232→
233→        // Rule 4: Accepted order cancellation rules
234→        if ($order->status === 'accepted') {
235→            $acceptedAt       = strtotime($order->accepted_at);
236→            $fiveMinutesLater = $acceptedAt + (5 * 60);
237→            $now              = time();
238→
239→            if ($now > $fiveMinutesLater) {
240→                // Past 5 minutes: reason_code required
241→                if (empty($reasonCode)) {
242→                    throw new ValidationException(
243→                        'Cancellation reason is required after the free cancellation window',
244→                        ['reason_code' => 'Reason code is required for late cancellations']
245→                    );
246→                }
247→
248→                // If OTHER, reason_text is required
249→                if ($reasonCode === 'OTHER' && empty($reasonText)) {
250→                    throw new ValidationException(
251→                        'Reason text is required when reason code is OTHER',
252→                        ['reason_text' => 'Please provide details for your cancellation reason']
253→                    );
254→                }
255→            }
256→            // Within 5 minutes: free cancel, no reason required
257→        }
258→
259→        // Rule 5: Apply cancellation
260→        $oldStatus = $order->status;
261→        $order->status             = 'canceled';
262→        $order->canceled_at        = date('Y-m-d\TH:i:s\Z');
263→        $order->cancel_reason_code = $reasonCode;
264→        $order->cancel_reason_text = $reasonText;
265→        $order->save();
266→
267→        // Restore listing to active
268→        $listing = Listing::find($order->listing_id);
269→        if ($listing) {
270→            $listing->status = 'active';
271→            $listing->save();
272→        }
273→
274→        // Rule 6: Record audit log
275→        $this->auditService->log(
276→            (int) $order->organization_id,
277→            $userId,
278→            'order.cancel',
279→            'order',
280→            $order->id,
281→            ['status' => $oldStatus],
282→            ['status' => 'canceled', 'reason_code' => $reasonCode, 'reason_text' => $reasonText]
283→        );
284→
285→        return $order;
286→    }
287→
288→    /**
289→     * Dispute a completed order (within 72 hours of completion).
290→     */
291→    public function dispute(int $orderId, int $userId, string $reason): Order
292→    {
293→        $order = $this->findOrderOrFail($orderId);
294→        $this->verifyParty($order, $userId);
295→
296→        if ($order->status !== 'completed') {
297→            throw new BusinessException(
298→                'Only completed orders can be disputed',
299→                40901,
300→                409
301→            );
302→        }
303→
304→        $completedAt     = strtotime($order->completed_at);
305→        $seventyTwoHours = $completedAt + (72 * 3600);
306→        if (time() > $seventyTwoHours) {
307→            throw new BusinessException(
308→                'Dispute window has expired (72 hours after completion)',
309→                40901,
310→                409
311→            );
312→        }
313→
314→        $oldStatus = $order->status;
315→        $order->status         = 'disputed';
316→        $order->disputed_at    = date('Y-m-d\TH:i:s\Z');
317→        $order->dispute_reason = $reason;
318→        $order->save();
319→
320→        // Update listing status
321→        $listing = Listing::find($order->listing_id);
322→        if ($listing) {
323→            $listing->status = 'disputed';
324→            $listing->save();
325→        }
326→
327→        $this->auditService->log(
328→            (int) $order->organization_id,
329→            $userId,
330→            'order.dispute',
331→            'order',
332→            $order->id,
333→            ['status' => $oldStatus],
334→            ['status' => 'disputed', 'reason' => $reason]
335→        );
336→
337→        return $order;
338→    }
339→
340→    /**
341→     * Resolve a disputed order (admin only, checked at route level).
342→     */
343→    public function resolve(int $orderId, string $resolution, string $outcome): Order
344→    {
345→        $order = $this->findOrderOrFail($orderId);
346→
347→        if ($order->status !== 'disputed') {
348→            throw new BusinessException(
349→                'Only disputed orders can be resolved',
350→                40901,
351→                409
352→            );
353→        }
354→
355→        $oldStatus = $order->status;
356→        $order->status             = 'resolved';
357→        $order->resolved_at        = date('Y-m-d\TH:i:s\Z');
358→        $order->resolution_notes   = $resolution;
359→        $order->resolution_outcome = $outcome;
360→        $order->save();
361→
362→        // Update listing status
363→        $listing = Listing::find($order->listing_id);
364→        if ($listing) {
365→            $listing->status = 'resolved';
366→            $listing->save();
367→        }
368→
369→        $this->auditService->log(
370→            (int) $order->organization_id,
371→            (int) request()->user->id,
372→            'order.resolve',
373→            'order',
374→            $order->id,
375→            ['status' => $oldStatus],
376→            ['status' => 'resolved', 'outcome' => $outcome]
377→        );
378→
379→        return $order;
380→    }
381→
382→    /**
383→     * Expire all pending orders that have passed their 30-minute window.
384→     */
385→    public function expirePendingOrders(): int
386→    {
387→        $cutoff = date('Y-m-d\TH:i:s\Z', strtotime('-30 minutes'));
388→
389→        $expiredOrders = Order::where('status', 'pending_match')
390→            ->where('created_at', '<', $cutoff)
391→            ->select();
392→
393→        $count = 0;
394→        foreach ($expiredOrders as $order) {
395→            $order->status = 'expired';
396→            $order->save();
397→
398→            // Restore listing to active
399→            $listing = Listing::find($order->listing_id);
400→            if ($listing && $listing->status === 'matched') {
401→                $listing->status = 'active';
402→                $listing->save();
403→            }
404→
405→            $count++;
406→        }
407→
408→        return $count;
409→    }
410→
411→    // ---- Private helpers ----
412→
413→    private function findOrderOrFail(int $orderId): Order
414→    {
415→        $order = Order::find($orderId);
416→        if (!$order) {
417→            throw new NotFoundException('Order not found');
418→        }
419→        return $order;
420→    }
421→
422→    private function verifyParty(Order $order, int $userId): void
423→    {
424→        if ((int) $order->passenger_id !== $userId && (int) $order->driver_id !== $userId) {
425→            throw new ForbiddenException('You are not a party to this order');
426→        }
427→    }
428→}
