  1→<?php
  2→declare(strict_types=1);
  3→
  4→namespace app\command;
  5→
  6→use app\model\BehaviorEvent;
  7→use app\model\DataLineage;
  8→use app\model\Organization;
  9→use think\console\Command;
 10→use think\console\Input;
 11→use think\console\Output;
 12→use think\facade\Db;
 13→use think\facade\Log;
 14→
 15→/**
 16→ * Deduplicate behavior events within 1-minute windows.
 17→ *
 18→ * For each organization, finds duplicate behavior_events that share the same
 19→ * user_id, event_type, target_type, and target_id within a 1-minute window.
 20→ * Keeps the earliest record, deletes duplicates.
 21→ *
 22→ * Idempotent: each run uses a unique run_id, creating separate lineage entries.
 23→ */
 24→class GovernanceDedupCommand extends Command
 25→{
 26→    protected function configure(): void
 27→    {
 28→        $this->setName('governance:dedup')
 29→             ->setDescription('Deduplicate behavior events within 1-minute windows');
 30→    }
 31→
 32→    protected function execute(Input $input, Output $output): int
 33→    {
 34→        $runId = $this->generateUuid();
 35→        $totalRemoved = 0;
 36→        $orgCount = 0;
 37→
 38→        $organizations = Organization::select();
 39→
 40→        foreach ($organizations as $org) {
 41→            $orgId = $org->id;
 42→
 43→            // Find all events for this org, ordered by created_at ascending
 44→            $events = BehaviorEvent::where('organization_id', $orgId)
 45→                ->order('user_id', 'asc')
 46→                ->order('event_type', 'asc')
 47→                ->order('target_type', 'asc')
 48→                ->order('target_id', 'asc')
 49→                ->order('created_at', 'asc')
 50→                ->select();
 51→
 52→            $inputCount = count($events);
 53→            $toDelete = [];
 54→            $seen = [];
 55→
 56→            foreach ($events as $event) {
 57→                $groupKey = implode('|', [
 58→                    $event->user_id,
 59→                    $event->event_type,
 60→                    $event->target_type,
 61→                    $event->target_id,
 62→                ]);
 63→
 64→                if (isset($seen[$groupKey])) {
 65→                    $lastTimestamp = $seen[$groupKey];
 66→                    $currentTimestamp = strtotime($event->created_at);
 67→                    $lastTime = strtotime($lastTimestamp);
 68→
 69→                    // Within 1-minute window: mark as duplicate
 70→                    if (abs($currentTimestamp - $lastTime) <= 60) {
 71→                        $toDelete[] = $event->id;
 72→                        continue;
 73→                    }
 74→                }
 75→
 76→                // Keep this event and update the group's latest timestamp
 77→                $seen[$groupKey] = $event->created_at;
 78→            }
 79→
 80→            if (!empty($toDelete)) {
 81→                // Delete in batches to avoid overly long queries
 82→                foreach (array_chunk($toDelete, 500) as $chunk) {
 83→                    BehaviorEvent::whereIn('id', $chunk)->delete();
 84→                }
 85→            }
 86→
 87→            $removedCount = count($toDelete);
 88→            $outputCount = $inputCount - $removedCount;
 89→            $totalRemoved += $removedCount;
 90→
 91→            if ($removedCount > 0) {
 92→                $orgCount++;
 93→            }
 94→
 95→            // Record lineage
 96→            DataLineage::create([
 97→                'organization_id' => $orgId,
 98→                'job_name'        => 'governance:dedup',
 99→                'run_id'          => $runId,
100→                'step'            => 'dedup_behavior_events',
101→                'input_count'     => $inputCount,
102→                'output_count'    => $outputCount,
103→                'removed_count'   => $removedCount,
104→                'details'         => null,
105→                'executed_at'     => date('Y-m-d H:i:s'),
106→            ]);
107→        }
108→
109→        Log::info("governance:dedup completed: removed {$totalRemoved} duplicates across {$orgCount} organizations (run_id={$runId})");
110→        $output->writeln("Dedup complete: removed {$totalRemoved} duplicate events across {$orgCount} organizations.");
111→
112→        return 0;
113→    }
114→
115→    /**
116→     * Generate a UUID v4.
117→     */
118→    private function generateUuid(): string
119→    {
120→        $data = random_bytes(16);
121→        $data[6] = chr(ord($data[6]) & 0x0f | 0x40); // version 4
122→        $data[8] = chr(ord($data[8]) & 0x3f | 0x80); // variant 1
123→
124→        return vsprintf('%s%s-%s-%s-%s-%s%s%s', str_split(bin2hex($data), 4));
125→    }
126→}
