  2→declare(strict_types=1);
  3→
  4→namespace unit_tests\review;
  5→
  6→use PHPUnit\Framework\TestCase;
  7→
  8→/**
  9→ * Tests for CredibilityService score computation.
 10→ *
 11→ * Credibility formula:
 12→ *   score = w_age * age_factor
 13→ *         + w_completion * completion_factor
 14→ *         + w_pattern * pattern_factor
 15→ *         + w_timing * timing_factor
 16→ *
 17→ * Weights: age=0.25, completion=0.30, pattern=0.25, timing=0.20
 18→ */
 19→class CredibilityScoreTest extends TestCase
 20→{
 21→    private const WEIGHTS = [
 22→        'age'        => 0.25,
 23→        'completion' => 0.30,
 24→        'pattern'    => 0.25,
 25→        'timing'     => 0.20,
 26→    ];
 27→
 28→    private function computeCredibility(
 29→        int $accountAgeDays,
 30→        int $completedOrders,
 31→        int $totalOrders,
 32→        int $recentFiveStarCount,
 33→        float $minutesSinceCompletion
 34→    ): float {
 35→        // Age factor
 36→        $ageFactor = $accountAgeDays < 14 ? 0.5 : 1.0;
 37→
 38→        // Completion factor
 39→        $completionFactor = $totalOrders > 0 ? $completedOrders / $totalOrders : 0.0;
 40→
 41→        // Pattern factor: penalize burst of 5-star reviews
 42→        $patternFactor = $recentFiveStarCount >= 3 ? 0.5 : 1.0;
 43→
 44→        // Timing factor: review within 5 min of completion is suspicious
 45→        $timingFactor = ($minutesSinceCompletion >= 0 && $minutesSinceCompletion <= 5) ? 0.5 : 1.0;
 46→
 47→        $score = self::WEIGHTS['age'] * $ageFactor
 48→               + self::WEIGHTS['completion'] * $completionFactor
 49→               + self::WEIGHTS['pattern'] * $patternFactor
 50→               + self::WEIGHTS['timing'] * $timingFactor;
 51→
 52→        return max(0.0, min(1.0, $score));
 53→    }
 54→
 55→    public function test_new_account_under_14_days_gets_half_age_factor(): void
 56→    {
 57→        // All other factors optimal: completion=1.0, pattern=1.0, timing=1.0
 58→        $score = $this->computeCredibility(7, 10, 10, 0, 60);
 59→
 60→        // age: 0.25 * 0.5 = 0.125
 61→        // completion: 0.30 * 1.0 = 0.30
 62→        // pattern: 0.25 * 1.0 = 0.25
 63→        // timing: 0.20 * 1.0 = 0.20
 64→        // total = 0.875
 65→        $this->assertEqualsWithDelta(0.875, $score, 0.001);
 66→    }
 67→
 68→    public function test_old_account_over_14_days_gets_full_age_factor(): void
 69→    {
 70→        $score = $this->computeCredibility(30, 10, 10, 0, 60);
 71→
 72→        // age: 0.25 * 1.0 = 0.25
 73→        // completion: 0.30 * 1.0 = 0.30
 74→        // pattern: 0.25 * 1.0 = 0.25
 75→        // timing: 0.20 * 1.0 = 0.20
 76→        // total = 1.0
 77→        $this->assertEqualsWithDelta(1.0, $score, 0.001);
 78→    }
 79→
 80→    public function test_completion_factor_is_ratio_of_completed_to_total(): void
 81→    {
 82→        // 5 out of 10 orders completed
 83→        $score = $this->computeCredibility(30, 5, 10, 0, 60);
 84→
 85→        // completion: 0.30 * 0.5 = 0.15
 86→        // total = 0.25 + 0.15 + 0.25 + 0.20 = 0.85
 87→        $this->assertEqualsWithDelta(0.85, $score, 0.001);
 88→    }
 89→
 90→    public function test_no_orders_gives_zero_completion_factor(): void
 91→    {
 92→        $score = $this->computeCredibility(30, 0, 0, 0, 60);
 93→
 94→        // completion: 0.30 * 0.0 = 0.0
 95→        // total = 0.25 + 0.0 + 0.25 + 0.20 = 0.70
 96→        $this->assertEqualsWithDelta(0.70, $score, 0.001);
 97→    }
 98→
 99→    public function test_burst_five_star_reviews_reduce_pattern_factor(): void
100→    {
101→        // 3 or more 5-star reviews in 24h
102→        $score = $this->computeCredibility(30, 10, 10, 5, 60);
103→
104→        // pattern: 0.25 * 0.5 = 0.125
105→        // total = 0.25 + 0.30 + 0.125 + 0.20 = 0.875
106→        $this->assertEqualsWithDelta(0.875, $score, 0.001);
107→    }
108→
109→    public function test_review_within_5_min_of_completion_penalized(): void
110→    {
111→        // Review at 3 minutes after completion
112→        $score = $this->computeCredibility(30, 10, 10, 0, 3);
113→
114→        // timing: 0.20 * 0.5 = 0.10
115→        // total = 0.25 + 0.30 + 0.25 + 0.10 = 0.90
116→        $this->assertEqualsWithDelta(0.90, $score, 0.001);
117→    }
118→
119→    public function test_score_clamped_between_0_and_1(): void
120→    {
121→        // All optimal factors should produce exactly 1.0
122→        $maxScore = $this->computeCredibility(30, 10, 10, 0, 60);
123→        $this->assertLessThanOrEqual(1.0, $maxScore);
124→        $this->assertGreaterThanOrEqual(0.0, $maxScore);
125→
126→        // Worst case: new account, no orders, burst 5-star, quick review
127→        $minScore = $this->computeCredibility(1, 0, 0, 5, 2);
128→        $this->assertLessThanOrEqual(1.0, $minScore);
129→        $this->assertGreaterThanOrEqual(0.0, $minScore);
130→    }
