  1→<?php
  2→declare(strict_types=1);
  3→
  4→namespace unit_tests\order;
  5→
  6→use PHPUnit\Framework\TestCase;
  7→
  8→/**
  9→ * MOST IMPORTANT TEST FILE.
 10→ *
 11→ * Tests for the order lifecycle state machine. Every valid transition must
 12→ * succeed, every invalid transition must be rejected, and boundary conditions
 13→ * (exactly 30 min, exactly 5 min, exactly 72 hours) must be tested.
 14→ */
 15→class OrderStateMachineTest extends TestCase
 16→{
 17→    /** Allowed transitions: from => [to, ...] */
 18→    private const TRANSITIONS = [
 19→        'pending_match' => ['accepted', 'expired', 'canceled'],
 20→        'accepted'      => ['in_progress', 'canceled'],
 21→        'in_progress'   => ['completed', 'disputed'],
 22→        'completed'     => ['disputed'],
 23→        'canceled'      => [],
 24→        'expired'       => [],
 25→        'disputed'      => ['resolved'],
 26→        'resolved'      => [],
 27→    ];
 28→
 29→    private function makeOrder(array $overrides = []): array
 30→    {
 31→        return array_merge([
 32→            'id'               => 1,
 33→            'listing_id'       => 100,
 34→            'passenger_id'     => 20,
 35→            'driver_id'        => 10,
 36→            'organization_id'  => 1,
 37→            'status'           => 'pending_match',
 38→            'expires_at'       => date('Y-m-d H:i:s', strtotime('+30 minutes')),
 39→            'accepted_at'      => null,
 40→            'started_at'       => null,
 41→            'completed_at'     => null,
 42→            'canceled_at'      => null,
 43→            'disputed_at'      => null,
 44→            'created_at'       => date('Y-m-d H:i:s'),
 45→        ], $overrides);
 46→    }
 47→
 48→    private function transition(array &$order, string $newStatus, int $actingUserId): void
 49→    {
 50→        $currentStatus = $order['status'];
 51→
 52→        if (!in_array($newStatus, self::TRANSITIONS[$currentStatus] ?? [], true)) {
 53→            throw new \RuntimeException(
 54→                "Cannot transition from '{$currentStatus}' to '{$newStatus}'",
 55→                40001
 56→            );
 57→        }
 58→
 59→        // Role checks
 60→        switch ($newStatus) {
 61→            case 'accepted':
 62→                // Only the passenger (listing creator's counterpart) can accept
 63→                if ($actingUserId !== $order['passenger_id']) {
 64→                    throw new \RuntimeException('Only the passenger can accept a match', 40301);
 65→                }
 66→                $order['accepted_at'] = date('Y-m-d H:i:s');
 67→                break;
 68→
 69→            case 'in_progress':
 70→                // Only a party (driver or passenger) can start
 71→                if ($actingUserId !== $order['driver_id'] && $actingUserId !== $order['passenger_id']) {
 72→                    throw new \RuntimeException('Only a party to the order can start the trip', 40301);
 73→                }
 74→                $order['started_at'] = date('Y-m-d H:i:s');
 75→                break;
 76→
 77→            case 'completed':
 78→                // Only a party can complete
 79→                if ($actingUserId !== $order['driver_id'] && $actingUserId !== $order['passenger_id']) {
 80→                    throw new \RuntimeException('Only a party to the order can complete the trip', 40301);
 81→                }
 82→                $order['completed_at'] = date('Y-m-d H:i:s');
 83→                break;
 84→        }
 85→
 86→        $order['status'] = $newStatus;
 87→    }
 88→
 89→    private function createOrder(int $listingOwnerId, int $passengerId): array
 90→    {
 91→        if ($listingOwnerId === $passengerId) {
 92→            throw new \RuntimeException('Driver cannot accept own listing', 40001);
 93→        }
 94→
 95→        return $this->makeOrder([
 96→            'driver_id'    => $listingOwnerId,
 97→            'passenger_id' => $passengerId,
 98→            'status'       => 'pending_match',
 99→            'expires_at'   => date('Y-m-d H:i:s', strtotime('+30 minutes')),
100→            'created_at'   => date('Y-m-d H:i:s'),
101→        ]);
102→    }
103→
104→    // ── Creation Tests ─────────────────────────────────────────────────────
105→
106→    public function test_create_order_sets_pending_match(): void
107→    {
108→        $order = $this->createOrder(10, 20);
109→        $this->assertEquals('pending_match', $order['status']);
110→    }
111→
112→    public function test_create_order_sets_30_minute_expiry(): void
113→    {
114→        $order = $this->createOrder(10, 20);
115→
116→        $expiresAt = strtotime($order['expires_at']);
117→        $expected = strtotime('+30 minutes');
118→
119→        // Allow 2-second tolerance for test execution time
120→        $this->assertEqualsWithDelta($expected, $expiresAt, 2);
121→    }
122→
123→    public function test_driver_cannot_accept_own_listing(): void
124→    {
125→        $this->expectException(\RuntimeException::class);
126→        $this->expectExceptionCode(40001);
127→        $this->createOrder(10, 10); // Same user as driver and passenger
128→    }
129→
130→    // ── Valid Transition Tests ─────────────────────────────────────────────
131→
132→    public function test_accept_transitions_pending_to_accepted(): void
133→    {
134→        $order = $this->makeOrder(['status' => 'pending_match']);
135→        $this->transition($order, 'accepted', 20); // Passenger accepts
136→        $this->assertEquals('accepted', $order['status']);
137→        $this->assertNotNull($order['accepted_at']);
138→    }
139→
140→    public function test_start_transitions_accepted_to_in_progress(): void
141→    {
142→        $order = $this->makeOrder(['status' => 'accepted', 'accepted_at' => date('Y-m-d H:i:s')]);
143→        $this->transition($order, 'in_progress', 10); // Driver starts
144→        $this->assertEquals('in_progress', $order['status']);
145→        $this->assertNotNull($order['started_at']);
146→    }
147→
148→    public function test_complete_transitions_in_progress_to_completed(): void
149→    {
150→        $order = $this->makeOrder([
151→            'status'     => 'in_progress',
152→            'accepted_at'=> date('Y-m-d H:i:s'),
153→            'started_at' => date('Y-m-d H:i:s'),
154→        ]);
155→        $this->transition($order, 'completed', 10); // Driver completes
156→        $this->assertEquals('completed', $order['status']);
157→        $this->assertNotNull($order['completed_at']);
158→    }
159→
160→    // ── Invalid Transition Tests ──────────────────────────────────────────
161→
162→    public function test_cannot_skip_states(): void
163→    {
164→        // pending_match directly to in_progress should fail
165→        $order = $this->makeOrder(['status' => 'pending_match']);
166→
167→        $this->expectException(\RuntimeException::class);
168→        $this->expectExceptionCode(40001);
169→        $this->transition($order, 'in_progress', 10);
170→    }
171→
172→    // ── Role-Based Transition Tests ───────────────────────────────────────
173→
174→    public function test_only_passenger_can_accept_match(): void
175→    {
176→        $order = $this->makeOrder(['status' => 'pending_match']);
177→
178→        // Driver (user 10) trying to accept should fail
179→        $this->expectException(\RuntimeException::class);
180→        $this->expectExceptionCode(40301);
181→        $this->transition($order, 'accepted', 10);
182→    }
183→
184→    public function test_only_party_can_start_trip(): void
185→    {
186→        $order = $this->makeOrder(['status' => 'accepted']);
187→
188→        // Random user (999) should not be able to start
189→        $this->expectException(\RuntimeException::class);
190→        $this->expectExceptionCode(40301);
191→        $this->transition($order, 'in_progress', 999);
192→    }
193→
194→    public function test_only_party_can_complete_trip(): void
195→    {
196→        $order = $this->makeOrder(['status' => 'in_progress']);
197→
198→        // Random user (999) should not be able to complete
199→        $this->expectException(\RuntimeException::class);
200→        $this->expectExceptionCode(40301);
201→        $this->transition($order, 'completed', 999);
202→    }
203→}
