  1→<?php
  2→declare(strict_types=1);
  3→
  4→namespace app\service;
  5→
  6→use app\model\Order;
  7→use app\model\Review;
  8→use app\model\User;
  9→
 10→class CredibilityService
 11→{
 12→    protected ModerationService $moderationService;
 13→
 14→    public function __construct()
 15→    {
 16→        $this->moderationService = new ModerationService();
 17→    }
 18→
 19→    /**
 20→     * Compute a credibility score for a user's review of an order.
 21→     */
 22→    public function compute(int $userId, int $orderId, int $orgId): float
 23→    {
 24→        $user  = User::find($userId);
 25→        $order = Order::find($orderId);
 26→
 27→        // Weights from env
 28→        $wAge        = (float) env('CREDIBILITY_WEIGHT_ACCOUNT_AGE', 0.3);
 29→        $wCompletion = (float) env('CREDIBILITY_WEIGHT_COMPLETION', 0.4);
 30→        $wPattern    = (float) env('CREDIBILITY_WEIGHT_PATTERN', 0.3);
 31→
 32→        // 1. age_factor: account older than 14 days => 1.0, else 0.5
 33→        $ageFactor = 1.0;
 34→        if ($user) {
 35→            $createdAt = strtotime($user->create_time ?? $user->created_at ?? 'now');
 36→            $daysSince = (time() - $createdAt) / 86400;
 37→            $ageFactor = $daysSince > 14 ? 1.0 : 0.5;
 38→        }
 39→
 40→        // 2. completion_factor: completed / total orders
 41→        $completionFactor = 0.0;
 42→        if ($user) {
 43→            $totalOrders = Order::where(function ($query) use ($userId) {
 44→                $query->where('passenger_id', $userId)
 45→                    ->whereOr('driver_id', $userId);
 46→            })->where('organization_id', $orgId)->count();
 47→
 48→            $completedOrders = Order::where(function ($query) use ($userId) {
 49→                $query->where('passenger_id', $userId)
 50→                    ->whereOr('driver_id', $userId);
 51→            })->where('organization_id', $orgId)
 52→              ->where('status', 'completed')
 53→              ->count();
 54→
 55→            $completionFactor = $totalOrders > 0 ? ($completedOrders / $totalOrders) : 0.0;
 56→        }
 57→
 58→        // 3. pattern_factor: start at 1.0, check anomalies
 59→        $patternFactor = 1.0;
 60→
 61→        // Anomaly check 1: Count 5-star reviews in the last hour
 62→        $oneHourAgo    = date('Y-m-d\TH:i:s\Z', strtotime('-1 hour'));
 63→        $fiveStarCount = Review::where('user_id', $userId)
 64→            ->where('organization_id', $orgId)
 65→            ->where('rating', 5)
 66→            ->where('created_at', '>', $oneHourAgo)
 67→            ->count();
 68→
 69→        if ($fiveStarCount >= 3) {
 70→            $patternFactor -= 0.25 * ($fiveStarCount - 2);
 71→        }
 72→
 73→        // Anomaly check 2: Review posted within 5 min of order completion
 74→        if ($order && $order->completed_at) {
 75→            $completedTime = strtotime($order->completed_at);
 76→            $now           = time();
 77→            $minutesSince  = ($now - $completedTime) / 60;
 78→
 79→            if ($minutesSince <= 5) {
 80→                $patternFactor -= 0.25;
 81→            }
 82→        }
 83→
 84→        // Anomaly check 3: Near-identical text (trigram > 0.9) with same rating
 85→        $recentReviews = Review::where('user_id', $userId)
 86→            ->where('organization_id', $orgId)
 87→            ->where('created_at', '>', date('Y-m-d\TH:i:s\Z', strtotime('-30 days')))
 88→            ->select();
 89→
 90→        // We need the current review text if it exists; check if there's a review for this order
 91→        $currentReview = Review::where('user_id', $userId)
 92→            ->where('order_id', $orderId)
 93→            ->find();
 94→
 95→        if ($currentReview) {
 96→            foreach ($recentReviews as $recent) {
 97→                if ($recent->id === $currentReview->id) {
 98→                    continue;
 99→                }
100→                if ((int) $recent->rating === (int) $currentReview->rating) {
101→                    $similarity = $this->moderationService->trigramJaccard(
102→                        $currentReview->text,
103→                        $recent->text
104→                    );
105→                    if ($similarity > 0.9) {
106→                        $patternFactor -= 0.25;
107→                        break; // Only subtract once for this anomaly
108→                    }
109→                }
110→            }
111→        }
112→
113→        // Clamp pattern_factor to [0.0, 1.0]
114→        $patternFactor = max(0.0, min(1.0, $patternFactor));
115→
116→        // 5. Final score
117→        $score = ($wAge * $ageFactor) + ($wCompletion * $completionFactor) + ($wPattern * $patternFactor);
118→
119→        // Clamp to [0.0, 1.0]
120→        return max(0.0, min(1.0, round($score, 4)));
121→    }
122→
123→    /**
124→     * Recompute credibility scores for all reviews in an organization.
125→     */
126→    public function recomputeAll(int $orgId): int
127→    {
128→        $reviews = Review::where('organization_id', $orgId)->select();
129→        $count   = 0;
130→
131→        foreach ($reviews as $review) {
132→            $newScore = $this->compute(
133→                (int) $review->user_id,
134→                (int) $review->order_id,
135→                $orgId
136→            );
137→
138→            $review->credibility_score = $newScore;
139→            $review->save();
140→            $count++;
141→        }
142→
143→        return $count;
144→    }
145→}
