 2→declare(strict_types=1);
 3→
 4→namespace app\middleware;
 5→
 6→use app\exception\ForbiddenException;
 7→use think\Request;
 8→use think\Response;
 9→
10→/**
11→ * Role-based access control middleware.
12→ *
13→ * Receives a dot-separated permission string via the route definition:
14→ *   ->middleware('rbac:listing.create')
15→ *
16→ * The string is split into a resource and an action, and the authenticated
17→ * user's permission set is checked via User::hasPermission().
18→ */
19→class RbacMiddleware
20→{
21→    /**
22→     * @param Request  $request
23→     * @param \Closure $next
24→     * @param string   $permission  Dot-separated "resource.action"
25→     * @return Response
26→     * @throws ForbiddenException
27→     */
28→    public function handle(Request $request, \Closure $next, string $permission): Response
29→    {
30→        [$resource, $action] = $this->parsePermission($permission);
31→
32→        if (!$request->user->hasPermission($resource, $action)) {
33→            throw new ForbiddenException(
34→                "You do not have permission to {$action} {$resource}",
35→                40301
36→            );
37→        }
38→
39→        return $next($request);
40→    }
41→
42→    /**
43→     * Split a permission string into resource and action components.
44→     *
45→     * @param string $permission
46→     * @return array{0: string, 1: string}
47→     */
48→    private function parsePermission(string $permission): array
49→    {
50→        $parts = explode('.', $permission, 2);
51→
52→        if (count($parts) !== 2 || $parts[0] === '' || $parts[1] === '') {
53→            throw new \InvalidArgumentException(
54→                "Invalid permission format '{$permission}'. Expected 'resource.action'."
55→            );
56→        }
57→
58→        return [$parts[0], $parts[1]];
59→    }
60→}
